(self.webpackChunkcheatsheet=self.webpackChunkcheatsheet||[]).push([[3626],{3687:(e,t,l)=>{"use strict";l.r(t),l.d(t,{data:()=>a});const a={key:"v-015689f3",path:"/python/data-type/tuple/",title:"Tuples",lang:"en-US",frontmatter:{},excerpt:"",headers:[{level:2,title:"การสร้างตัวแปรแบบ Tuple",slug:"การสร้างตัวแปรแบบ-tuple",children:[]}],filePathRelative:"python/data-type/tuple/README.md",git:{updatedTime:162676698e4,contributors:[]}}},2352:(e,t,l)=>{"use strict";l.r(t),l.d(t,{default:()=>u});const a=(0,l(6252).uE)('<h1 id="tuples" tabindex="-1"><a class="header-anchor" href="#tuples" aria-hidden="true">#</a> Tuples</h1><p>ข้อมูลที่ถูกเก็บเป็นประเภท Tuple จะแตกต่างกับ Tuple โดยที่</p><ul><li>ไม่่สามารถเอาข้อมูลเข้าไปอีกได้ หลังการสร้างแล้ว</li><li>ไม่สามารถลบข้อมูลได้</li><li>หากว่าจะลบ ต้องลบทั้งหมด แล้วทำใหม่</li></ul><p>ดังนั้น Tuple จึงมีประโยชน์กับการใช้งาน</p><ul><li>ข้อมูลที่ตาตัว</li><li>ข้อมูลที่น้องเขียนเอง แล้วไม่ต้องการเปลี่ยนแปลงภายหลัง</li></ul><p>โดยการใช้งานจะเหมือน List เลย น้องๆสามารถเข้าไปดูวิธีการใช้งานได้ที่หน้า List นะครับ</p><h2 id="การสร้างตัวแปรแบบ-tuple" tabindex="-1"><a class="header-anchor" href="#การสร้างตัวแปรแบบ-tuple" aria-hidden="true">#</a> การสร้างตัวแปรแบบ Tuple</h2><div class="language-Python ext-Python line-numbers-mode"><pre class="language-Python"><code>text = (&#39;k&#39;, &#39;u&#39;, &#39;m&#39;, &#39;a&#39;, &#39;m&#39;, &#39;o&#39;, &#39;n&#39;)\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>สังเกตได้ว่า จะใช้ () แทน [] เพื่อบ่งบอกความเป็น Tuple ของมัน</p>',9),u={render:function(e,t){return a}}}}]);